/**
 * Tests for MusicLibrary and related helpers
 */

import {
  MusicLibrary,
  MusicTrack,
  MusicCategory,
  MusicMood,
  MusicFilter,
  getMusicLibrary,
  getExtendedMusicLibrary,
  formatDuration,
  getCategoryDisplayName,
  getMoodDisplayName,
} from '@/lib/audio/music-library';

// =============================================================================
// MusicLibrary Class
// =============================================================================

describe('MusicLibrary', () => {
  let library: MusicLibrary;

  beforeEach(() => {
    library = new MusicLibrary();
  });

  describe('getCatalog', () => {
    it('returns the full catalog including tracks without URLs', () => {
      const catalog = library.getCatalog();
      expect(catalog.length).toBeGreaterThan(0);
      // All built-in tracks have empty URLs
      expect(catalog.every((t) => t.id && t.title)).toBe(true);
    });

    it('each track has required fields', () => {
      const catalog = library.getCatalog();
      for (const track of catalog) {
        expect(track.id).toBeDefined();
        expect(track.title).toBeDefined();
        expect(track.artist).toBeDefined();
        expect(track.category).toBeDefined();
        expect(track.mood).toBeDefined();
        expect(typeof track.duration).toBe('number');
        expect(typeof track.bpm).toBe('number');
        expect(typeof track.isLoop).toBe('boolean');
        expect(track.license).toBeDefined();
        expect(track.tags.length).toBeGreaterThan(0);
      }
    });
  });

  describe('getAllTracks', () => {
    it('returns empty array when no tracks have URLs (default)', () => {
      // Default built-in tracks have url: '' (empty) so they are unavailable
      const available = library.getAllTracks(false);
      expect(available.length).toBe(0);
    });

    it('returns all tracks when includeUnavailable=true', () => {
      const all = library.getAllTracks(true);
      expect(all.length).toBeGreaterThan(0);
    });
  });

  describe('isTrackAvailable', () => {
    it('returns false for tracks without URL', () => {
      expect(library.isTrackAvailable('corp-01')).toBe(false);
    });

    it('returns false for non-existent track', () => {
      expect(library.isTrackAvailable('nonexistent')).toBe(false);
    });

    it('returns true for tracks with URL', () => {
      library.addTrack({
        id: 'test-track',
        title: 'Test',
        artist: 'Test',
        category: 'ambient',
        mood: ['calm'],
        duration: 60,
        bpm: 100,
        url: 'https://example.com/test.mp3',
        license: 'royalty-free',
        tags: ['test'],
        isLoop: false,
      });
      expect(library.isTrackAvailable('test-track')).toBe(true);
    });
  });

  describe('getTrack', () => {
    it('returns track by ID', () => {
      const track = library.getTrack('corp-01');
      expect(track).toBeDefined();
      expect(track?.title).toBe('Corporate Success');
    });

    it('returns undefined for non-existent ID', () => {
      expect(library.getTrack('nonexistent')).toBeUndefined();
    });

    it('resolves alias IDs (frontend → library)', () => {
      const track = library.getTrack('corporate-1');
      expect(track).toBeDefined();
      expect(track?.id).toBe('corp-01');
    });

    it('resolves calm alias', () => {
      const track = library.getTrack('calm-1');
      expect(track).toBeDefined();
      expect(track?.id).toBe('amb-01');
    });

    it('resolves inspiring alias', () => {
      const track = library.getTrack('inspiring-1');
      expect(track).toBeDefined();
      expect(track?.id).toBe('motiv-01');
    });
  });

  describe('filterTracks', () => {
    it('filters by category', () => {
      const filtered = library.filterTracks({ category: 'corporate', includeUnavailable: true });
      expect(filtered.length).toBeGreaterThan(0);
      expect(filtered.every((t) => t.category === 'corporate')).toBe(true);
    });

    it('filters by mood', () => {
      const filtered = library.filterTracks({ moods: ['calm'], includeUnavailable: true });
      expect(filtered.length).toBeGreaterThan(0);
      expect(filtered.every((t) => t.mood.includes('calm'))).toBe(true);
    });

    it('filters by minimum duration', () => {
      const filtered = library.filterTracks({ minDuration: 250, includeUnavailable: true });
      expect(filtered.length).toBeGreaterThan(0);
      expect(filtered.every((t) => t.duration >= 250)).toBe(true);
    });

    it('filters by maximum duration', () => {
      const filtered = library.filterTracks({ maxDuration: 180, includeUnavailable: true });
      expect(filtered.length).toBeGreaterThan(0);
      expect(filtered.every((t) => t.duration <= 180)).toBe(true);
    });

    it('filters by BPM range', () => {
      const filtered = library.filterTracks({ minBpm: 100, maxBpm: 120, includeUnavailable: true });
      expect(filtered.length).toBeGreaterThan(0);
      expect(filtered.every((t) => t.bpm >= 100 && t.bpm <= 120)).toBe(true);
    });

    it('filters by isLoop', () => {
      const loops = library.filterTracks({ isLoop: true, includeUnavailable: true });
      expect(loops.every((t) => t.isLoop)).toBe(true);

      const nonLoops = library.filterTracks({ isLoop: false, includeUnavailable: true });
      expect(nonLoops.every((t) => !t.isLoop)).toBe(true);
    });

    it('filters by search text (title)', () => {
      const filtered = library.filterTracks({ search: 'corporate', includeUnavailable: true });
      expect(filtered.length).toBeGreaterThan(0);
    });

    it('filters by search text (tag)', () => {
      const filtered = library.filterTracks({ search: 'business', includeUnavailable: true });
      expect(filtered.length).toBeGreaterThan(0);
    });

    it('filters by search text (artist)', () => {
      const filtered = library.filterTracks({ search: 'studio', includeUnavailable: true });
      expect(filtered.length).toBeGreaterThan(0);
    });

    it('combines multiple filters', () => {
      const filtered = library.filterTracks({
        category: 'ambient',
        moods: ['calm'],
        minDuration: 200,
        includeUnavailable: true,
      });
      expect(filtered.length).toBeGreaterThan(0);
      expect(filtered.every((t) => t.category === 'ambient' && t.mood.includes('calm') && t.duration >= 200)).toBe(true);
    });

    it('returns empty array when no matches', () => {
      const filtered = library.filterTracks({ search: 'xyznotexist', includeUnavailable: true });
      expect(filtered).toEqual([]);
    });
  });

  describe('playlists', () => {
    it('getAllPlaylists returns default playlists', () => {
      const playlists = library.getAllPlaylists();
      expect(playlists.length).toBeGreaterThan(0);
    });

    it('getPlaylist returns playlist by ID', () => {
      const playlist = library.getPlaylist('nr-training');
      expect(playlist).toBeDefined();
      expect(playlist?.name).toBe('Treinamentos NR');
      expect(playlist?.trackIds.length).toBeGreaterThan(0);
    });

    it('getPlaylist returns undefined for non-existent', () => {
      expect(library.getPlaylist('nonexistent')).toBeUndefined();
    });

    it('getPlaylistTracks returns empty for tracks without URLs', () => {
      // Default tracks have empty URLs
      const tracks = library.getPlaylistTracks('nr-training');
      expect(tracks).toEqual([]);
    });

    it('getPlaylistTracks returns empty for non-existent playlist', () => {
      const tracks = library.getPlaylistTracks('nonexistent');
      expect(tracks).toEqual([]);
    });

    it('createPlaylist adds new playlist', () => {
      library.createPlaylist({
        id: 'custom-1',
        name: 'Custom Playlist',
        description: 'Test playlist',
        trackIds: ['corp-01', 'amb-01'],
      });
      const playlist = library.getPlaylist('custom-1');
      expect(playlist).toBeDefined();
      expect(playlist?.name).toBe('Custom Playlist');
    });
  });

  describe('addTrack', () => {
    it('adds a new track to the library', () => {
      const newTrack: MusicTrack = {
        id: 'custom-track-1',
        title: 'Custom Track',
        artist: 'Test Artist',
        category: 'ambient',
        mood: ['calm', 'minimal'],
        duration: 120,
        bpm: 80,
        url: 'https://example.com/track.mp3',
        license: 'royalty-free',
        tags: ['custom', 'test'],
        isLoop: true,
      };
      library.addTrack(newTrack);
      const retrieved = library.getTrack('custom-track-1');
      expect(retrieved).toBeDefined();
      expect(retrieved?.title).toBe('Custom Track');
    });
  });

  describe('getRecommendedForNR', () => {
    it('returns tracks for NR-10 (eletricidade)', () => {
      const tracks = library.getRecommendedForNR('NR-10');
      // Returns empty because tracks don't have URLs, but the filter logic is correct
      expect(Array.isArray(tracks)).toBe(true);
    });

    it('returns tracks for unknown NR type', () => {
      const tracks = library.getRecommendedForNR('NR-99');
      expect(Array.isArray(tracks)).toBe(true);
    });
  });

  describe('getCategories', () => {
    it('returns empty when no tracks have URLs', () => {
      const categories = library.getCategories();
      expect(categories).toEqual([]);
    });

    it('returns categories after adding tracks with URLs', () => {
      library.addTrack({
        id: 'url-track',
        title: 'URL Track',
        artist: 'Test',
        category: 'corporate',
        mood: ['professional'],
        duration: 100,
        bpm: 100,
        url: 'https://example.com/track.mp3',
        license: 'royalty-free',
        tags: ['test'],
        isLoop: false,
      });
      const categories = library.getCategories();
      expect(categories.length).toBe(1);
      expect(categories[0].category).toBe('corporate');
      expect(categories[0].count).toBe(1);
    });
  });
});

// =============================================================================
// Singletons
// =============================================================================

describe('Singleton instances', () => {
  it('getMusicLibrary returns same instance', () => {
    const a = getMusicLibrary();
    const b = getMusicLibrary();
    expect(a).toBe(b);
  });

  it('getExtendedMusicLibrary returns same instance', () => {
    const a = getExtendedMusicLibrary();
    const b = getExtendedMusicLibrary();
    expect(a).toBe(b);
  });
});

// =============================================================================
// Helper Functions
// =============================================================================

describe('formatDuration', () => {
  it('formats 0 seconds', () => {
    expect(formatDuration(0)).toBe('0:00');
  });

  it('formats less than a minute', () => {
    expect(formatDuration(45)).toBe('0:45');
  });

  it('formats exact minute', () => {
    expect(formatDuration(60)).toBe('1:00');
  });

  it('formats minutes and seconds', () => {
    expect(formatDuration(183)).toBe('3:03');
  });

  it('pads seconds with leading zero', () => {
    expect(formatDuration(65)).toBe('1:05');
  });
});

describe('getCategoryDisplayName', () => {
  it('returns Portuguese name for corporate', () => {
    expect(getCategoryDisplayName('corporate')).toBe('Corporativo');
  });

  it('returns Portuguese name for training', () => {
    expect(getCategoryDisplayName('training')).toBe('Treinamento');
  });

  it('returns Portuguese name for calm', () => {
    expect(getCategoryDisplayName('calm')).toBe('Calmo');
  });

  it('returns Portuguese name for all categories', () => {
    const categories: MusicCategory[] = [
      'corporate', 'training', 'motivational', 'ambient',
      'technology', 'documentary', 'uplifting', 'calm',
    ];
    for (const cat of categories) {
      expect(getCategoryDisplayName(cat)).toBeDefined();
      expect(typeof getCategoryDisplayName(cat)).toBe('string');
    }
  });
});

describe('getMoodDisplayName', () => {
  it('returns Portuguese name for professional', () => {
    expect(getMoodDisplayName('professional')).toBe('Profissional');
  });

  it('returns Portuguese name for energetic', () => {
    expect(getMoodDisplayName('energetic')).toBe('Energético');
  });

  it('returns Portuguese name for all moods', () => {
    const moods: MusicMood[] = [
      'professional', 'energetic', 'calm', 'inspiring', 'serious',
      'friendly', 'modern', 'classic', 'minimal', 'dramatic',
    ];
    for (const mood of moods) {
      expect(getMoodDisplayName(mood)).toBeDefined();
      expect(typeof getMoodDisplayName(mood)).toBe('string');
    }
  });
});
